package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithQuoteMode() {
        // Create a mock CSVFormat object
        CSVFormat csvFormat = mock(CSVFormat.class);

        // Define the QuoteMode to be set
        QuoteMode quoteMode = QuoteMode.ALL;

        // Mock the behavior of the private constructor
        when(csvFormat.withQuoteMode(quoteMode)).thenCallRealMethod();

        // Call the method under test
        CSVFormat result = csvFormat.withQuoteMode(quoteMode);

        // Validate the result
        assertEquals(quoteMode, result.getQuoteMode());
    }
}
